import { Category } from "../model/categoryModel";

export const fetchSubcategories = async (categoryId: number): Promise<Category[]> => {
    try {
        const response = await fetch(`/api/categories/subcategories/${categoryId}`);
        console.log("📩 Fetch response:", response); // Debugging: Check if response is coming

        if (!response.ok) {  // ✅ Check for errors
            throw new Error(`Server responded with ${response.status}`);
        }

        const data = await response.json(); // ✅ Extract JSON data
        console.log("✅ Subcategories fetched:", data); // Debug logs
        return data as Category[];
    } catch (error) {
        console.error("❌ Failed to fetch subcategories:", error);
        return [];
    }
};
